function solve(words) {
    const n = words.length;
    if (n === 0) return [];
    if (n === 1) return [0];

    // Compute lcp_pairs
    const lcp_pairs = [];
    for (let i = 0; i < n - 1; i++) {
        lcp_pairs.push(lcp(words[i], words[i+1]));
    }

    // Compute prefix_max and suffix_max
    const prefix_max = new Array(n-1).fill(0);
    const suffix_max = new Array(n-1).fill(0);

    prefix_max[0] = lcp_pairs[0];
    for (let i = 1; i < n-1; i++) {
        prefix_max[i] = Math.max(prefix_max[i-1], lcp_pairs[i]);
    }

    suffix_max[n-2] = lcp_pairs[n-2];
    for (let i = n-3; i >= 0; i--) {
        suffix_max[i] = Math.max(suffix_max[i+1], lcp_pairs[i]);
    }

    // Now, for each i, compute answer
    const answer = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        if (n === 1) {
            answer[i] = 0;
            continue;
        }

        if (i === 0) {
            // Excluded pair is 0
            if (n-1 >= 1) {
                // modified array has length n-1 >= 1. If n-1 >=2, then there are pairs.
                // max_val is max of lcp_pairs[1..n-2]
                if (n-2 >= 1) {
                    max_val = suffix_max[1];
                } else {
                    max_val = 0;
                }
            } else {
                // n-1 is 1, so modified array has length 1. No adjacent pairs. answer is 0.
                max_val = 0;
            }
            answer[i] = max_val;
        } else if (i === n-1) {
            // Excluded pair is n-2
            if (n-2 >= 1) {
                // modified array has length n-1 >=1. If n-1 >=2, then there are pairs.
                // max_val is max of lcp_pairs[0..n-3]
                if (n-3 >= 0) {
                    max_val = prefix_max[n-3];
                } else {
                    max_val = 0;
                }
            } else {
                // n-1 is 1, so modified array has length 1. answer is 0.
                max_val = 0;
            }
            answer[i] = max_val;
        } else {
            // i is not 0 or n-1. Need to compute max_val from lcp_pairs excluding i-1 and i.
            let left_max = 0;
            let right_max = 0;

            // left part is 0..i-2
            if (i-2 >= 0) {
                left_max = prefix_max[i-2];
            } else {
                left_max = 0;
            }

            // right part is i+1..n-2
            if (i+1 < n-1) {
                right_max = suffix_max[i+1];
            } else {
                right_max = 0;
            }

            max_val = Math.max(left_max, right_max);

            // Check if there's a new pair (i-1, i+1)
            // compute LCP between words[i-1] and words[i+1]
            const new_lcp = lcp(words[i-1], words[i+1]);
            answer[i] = Math.max(max_val, new_lcp);
        }
    }

